class Tweet(namedtuple("Tweet", "user id timestamp fullname text")):
    @classmethod
    def from_soup(cls, tweet):
        return cls(
            user=tweet.find('span', 'username').text.encode(),
            id=tweet['data-item-id'],
            timestamp=tweet.find('a', 'tweet-timestamp')['title'],
            fullname=tweet.find('strong', 'fullname').text.encode(),
            text=tweet.find('p', 'tweet-text').text.encode()
