import sys
import os, os.path
from io import open
import glob, time

from lark.reconstruct import Reconstructor

from lark import Lark
from lark.indenter import Indenter

# __path__ = os.path.dirname(__file__)

class PythonIndenter(Indenter):
    NL_type = 'NEWLINE'
    OPEN_PAREN_types = ['LPAR', 'LSQB', 'LBRACE']
    CLOSE_PAREN_types = ['RPAR', 'RSQB', 'RBRACE']
    INDENT_type = 'INDENT'
    DEDENT_type = 'DEDENT'
    tab_len = 8

kwargs = dict(rel_to=__file__, postlex=PythonIndenter(), start='file_input')

python_parser3 = Lark.open('C:/Users/jmalar1/PycharmProjects/Lassi/ਲੱਸੀ/Extensions/ਪੈਧਾਨ_੩/ਪੈਧਾਨ ੩.lark',parser='lalr', **kwargs)

def _read(fn, *args):
    kwargs = {'encoding': 'iso-8859-1'}
    with open(fn, *args, **kwargs) as f:
        return f.read()

def _get_lib_path():
    if os.name == 'nt':
        if 'PyPy' in sys.version:
            return os.path.join(sys.prefix, 'lib-python', sys.winver)
        else:
            return os.path.join(sys.prefix, 'Lib')
    else:
        return [x for x in sys.path if x.endswith('%s.%s' % sys.version_info[:2])][0]

def test_python_lib():

    path = _get_lib_path()

    files = glob.glob(path+'/*.py')
    Recons = Reconstructor(python_parser3)

    start = time.time()

    for f in files:
        print( f , end=" ")
        try:
            start_file = time.time()
            tree = python_parser3.parse(_read(os.path.join(path, f)) + '\n')
            new = Recons.reconstruct(tree)
            print(round(time.time() - start_file, 2))
        except:
            print ('At %s' % f)
            raise

    end = time.time()
    print( "test_python_lib (%d files), time: %s secs"%(len(files), end-start) )


if __name__ == '__main__':
    test_python_lib()
